To implement a stack of a specified size using C++, you can create a class that internally uses an array to hold the elements. Here's an example implementation:

```cpp
#include <iostream>

class Stack {
private:
    int* array;
    int top;
    int size;

public:
    Stack(int maxSize) {
        size = maxSize;
        array = new int[size];
        top = -1;
    }

    ~Stack() {
        delete[] array;
    }

    bool isEmpty() {
        return top == -1;
    }

    bool isFull() {
        return top == size - 1;
    }

    void push(int value) {
        if (isFull()) {
            std::cout << "Stack is full. Unable to push element." << std::endl;
        } else {
            ++top;
            array[top] = value;
            std::cout << "Pushed element: " << value << std::endl;
        }
    }

    void pop() {
        if (isEmpty()) {
            std::cout << "Stack is empty. Unable to pop element." << std::endl;
        } else {
            std::cout << "Popped element: " << array[top] << std::endl;
            --top;
        }
    }

    int peek() {
        if (isEmpty()) {
            std::cout << "Stack is empty." << std::endl;
            return -1; // Placeholder value to indicate empty stack
        }
        return array[top];
    }
};

int main() {
    Stack stack(5); // Create a stack of size 5

    stack.push(10);
    stack.push(20);
    stack.push(30);
    stack.push(40);
    stack.push(50);
    stack.push(60); // Stack is full, unable to push

    std::cout << "Top element: " << stack.peek() << std::endl;

    stack.pop();
    stack.pop();
    stack.pop();
    stack.pop();
    stack.pop();
    stack.pop(); // Stack is empty, unable to pop

    return 0;
}
```

In this example, the `Stack` class is defined with member functions for operations such as `push()`, `pop()`, `peek()`, and helper functions `isEmpty()` and `isFull()`. The stack is implemented using a dynamically allocated array. The `size` parameter is specified during the creation of the `Stack` object.

You can modify the value of `maxSize` while creating the `Stack` object to adjust the desired size of the stack.

To implement a queue of a specified size using C++, you can create a class that internally uses an array to hold the elements. Here's an example implementation:

```cpp
#include <iostream>

class Queue {
private:
    int* array;
    int front;
    int rear;
    int size;
    int count;

public:
    Queue(int maxSize) {
        size = maxSize;
        array = new int[size];
        front = 0;
        rear = -1;
        count = 0;
    }

    ~Queue() {
        delete[] array;
    }

    bool isEmpty() {
        return count == 0;
    }

    bool isFull() {
        return count == size;
    }

    void enqueue(int value) {
        if (isFull()) {
            std::cout << "Queue is full. Unable to enqueue element." << std::endl;
        } else {
            rear = (rear + 1) % size;
            array[rear] = value;
            ++count;
            std::cout << "Enqueued element: " << value << std::endl;
        }
    }

    void dequeue() {
        if (isEmpty()) {
            std::cout << "Queue is empty. Unable to dequeue element." << std::endl;
        } else {
            std::cout << "Dequeued element: " << array[front] << std::endl;
            front = (front + 1) % size;
            --count;
        }
    }

    int peek() {
        if (isEmpty()) {
            std::cout << "Queue is empty." << std::endl;
            return -1; // Placeholder value to indicate empty queue
        }
        return array[front];
    }
};

int main() {
    Queue queue(5); // Create a queue of size 5

    queue.enqueue(10);
    queue.enqueue(20);
    queue.enqueue(30);
    queue.enqueue(40);
    queue.enqueue(50);
    queue.enqueue(60); // Queue is full, unable to enqueue

    std::cout << "Front element: " << queue.peek() << std::endl;

    queue.dequeue();
    queue.dequeue();
    queue.dequeue();
    queue.dequeue();
    queue.dequeue();
    queue.dequeue(); // Queue is empty, unable to dequeue

    return 0;
}
```

In this example, the `Queue` class is defined with member functions for operations such as `enqueue()`, `dequeue()`, `peek()`, and helper functions `isEmpty()` and `isFull()`. The queue is implemented using a dynamically allocated array. The `maxSize` parameter is specified during the creation of the `Queue` object.

You can modify the value of `maxSize` while creating the `Queue` object to adjust the desired size of the queue.

The `std::queue` container in C++ is typically implemented as a dynamic structure with no direct control over its size. However, if you need a queue with a fixed size, you can achieve it by creating a wrapper class around `std::queue` that enforces the size limitation. Here's an example implementation:

```cpp
#include <iostream>
#include <queue>

template<typename T>
class SizedQueue {
private:
    std::queue<T> queue;
    std::size_t maxSize;

public:
    SizedQueue(std::size_t size) : maxSize(size) {}

    void enqueue(const T& value) {
        if (queue.size() < maxSize) {
            queue.push(value);
            std::cout << "Enqueued element: " << value << std::endl;
        } else {
            std::cout << "Queue is full. Unable to enqueue element." << std::endl;
        }
    }

    void dequeue() {
        if (!queue.empty()) {
            std::cout << "Dequeued element: " << queue.front() << std::endl;
            queue.pop();
        } else {
            std::cout << "Queue is empty. Unable to dequeue element." << std::endl;
        }
    }

    T front() const {
        return queue.front();
    }

    bool isEmpty() const {
        return queue.empty();
    }

    bool isFull() const {
        return queue.size() >= maxSize;
    }
};

int main() {
    SizedQueue<int> queue(5); // Create a queue of size 5

    queue.enqueue(10);
    queue.enqueue(20);
    queue.enqueue(30);
    queue.enqueue(40);
    queue.enqueue(50);
    queue.enqueue(60); // Queue is full, unable to enqueue

    std::cout << "Front element: " << queue.front() << std::endl;

    queue.dequeue();
    queue.dequeue();
    queue.dequeue();
    queue.dequeue();
    queue.dequeue();
    queue.dequeue(); // Queue is empty, unable to dequeue

    return 0;
}
```

In this example, the `SizedQueue` class is a wrapper around `std::queue` that enforces the size limitation. It provides functions like `enqueue()`, `dequeue()`, `front()`, `isEmpty()`, and `isFull()` to operate on the underlying `std::queue` while ensuring the size restriction is honored. The `maxSize` parameter is specified during the creation of the `SizedQueue` object.

Note that you may need to include additional headers and adapt the implementation based on your specific requirements.
